const raw = $input.item.json;
// Support both direct data and webhook-wrapped data
const body = raw.body || raw;

const meetingId = body.meeting_id || body.id || '';
const title = body.title || body.meeting_title || '';
const summary = body.summary || body.ai_summary || '';
const transcript = body.transcript || body.full_transcript || '';
const actionItems = body.action_items || body.actionItems || [];
const duration = Number(body.duration || body.meeting_duration || 0);
const recordingUrl = body.recording_url || body.playback_url || '';
const meetingDate = body.meeting_date || body.date || body.start_time || new Date().toISOString();
const calendlyEventUri = body.calendly_event_uri || '';
const meetingType = body.meeting_type || 'discovery';

const transcriptStr = typeof transcript === 'string' ? transcript : '';
const readAiFromTranscript = (transcriptStr.match(/read\.ai\/analytics\/meetings\/([A-Za-z0-9]+)/i) || [])[1] || '';
const readAiMeetingId = String(meetingId || readAiFromTranscript || '').trim();

// Parse participants - handle both array and string
let participants = [];
if (Array.isArray(body.participants)) {
  participants = body.participants;
} else if (Array.isArray(body.attendees)) {
  participants = body.attendees;
} else if (typeof body.participants === 'string') {
  try { participants = JSON.parse(body.participants); } catch(e) { participants = []; }
}

const nextMeetingMap = {
  'discovery': 'onboarding',
  'onboarding': 'kickoff',
  'kickoff': 'progress_checkin',
  'progress_checkin': 'go_no_go',
  'go_no_go': 'delivery_review',
  'delivery_review': null
};
const nextMeetingType = nextMeetingMap[meetingType] || null;

// Find client participant (non-host)
const clientParticipant = participants.find(p => p && (p.is_host === false || p.is_organizer === false)) || participants[1] || {};
const clientEmail = body.client_email || clientParticipant.email || body.invitee_email || '';
const clientName = body.client_name || clientParticipant.name || body.invitee_name || '';

const fullContext = `Meeting Title: ${title}\nMeeting Type: ${meetingType}\n\nAI Summary:\n${summary}\n\nAction Items:\n${Array.isArray(actionItems) ? actionItems.map((item, i) => `${i+1}. ${typeof item === 'string' ? item : item.text || item.description || JSON.stringify(item)}`).join('\n') : actionItems}\n\nFull Transcript:\n${typeof transcript === 'string' ? transcript.substring(0, 15000) : JSON.stringify(transcript).substring(0, 15000)}`;

return [{
  json: {
    meetingId, readAiMeetingId, title, summary,
    transcript: typeof transcript === 'string' ? transcript : JSON.stringify(transcript),
    actionItems, participants, clientEmail, clientName,
    duration, recordingUrl, meetingDate, meetingType,
    nextMeetingType, calendlyEventUri, fullContext
  }
}];

const input = $input.item.json;
const readAiMeetingId = (input.readAiMeetingId || '').trim();
const baseUrl = $env.AMADUTOWN_PUBLIC_BASE_URL || 'https://amadutown.com';
const secret = $env.N8N_INGEST_SECRET || '';
let readAiDuplicate = false;
let existingMeetingRecordId = null;
if (readAiMeetingId && secret) {
  try {
    const res = await fetch(`${baseUrl}/api/read-ai-meeting-dedupe?read_ai_meeting_id=${encodeURIComponent(readAiMeetingId)}`, {
      headers: { Authorization: `Bearer ${secret}` }
    });
    const data = await res.json();
    readAiDuplicate = data.duplicate === true;
    existingMeetingRecordId = data.meeting_record_id || null;
  } catch (e) {
    readAiDuplicate = false;
  }
}
return [{ json: { ...input, readAiDuplicate, existingMeetingRecordId } }];

const meetingData = $('Extract Meeting Data').item.json;

// Safely get client project (may be empty if no match found)
let clientProject = {};
try {
  const cpItems = $('Fetch Client Project').all();
  if (cpItems.length > 0 && cpItems[0].json && cpItems[0].json.id) {
    clientProject = cpItems[0].json;
  }
} catch (e) {
  clientProject = {};
}

// Safely get prior meetings (may be empty)
let priorMeetings = [];
try {
  const pmItems = $('Fetch Prior Meetings').all();
  priorMeetings = pmItems.map(item => item.json).filter(m => m && m.id);
} catch (e) {
  priorMeetings = [];
}

const extractionSchemas = {
  discovery: '{"pain_points_discussed": ["specific business problems"], "solutions_proposed": ["solutions discussed"], "timeline_preference": "timeline", "budget_confirmed": "budget range", "decision_makers": ["stakeholders"], "competitor_mentions": ["competitors"], "fit_assessment": "hot|warm|cold"}',
  onboarding: '{"tools_agreed": [{"name": "tool", "purpose": "why", "access_type": "shared|dedicated", "owner": "who"}], "access_requirements": [{"platform": "name", "credential_type": "type", "status": "granted|pending"}], "communication_plan": {"channel": "where", "cadence": "frequency", "escalation_path": "how"}, "timeline_confirmed": {"start_date": "date", "end_date": "date", "milestones": []}, "win_conditions": ["success criteria"], "client_questions": ["questions"], "artifact_handoff": {"format": "type", "delivery_method": "how", "review_process": "steps"}}',
  kickoff: '{"access_granted": [{"platform": "name", "status": "granted|partial", "notes": "details"}], "access_pending": [{"platform": "name", "blocker": "why", "owner": "who", "due_date": "when"}], "milestone_dates_confirmed": [{"phase": "name", "description": "what", "target_date": "when"}], "roles_assigned": [{"person": "name", "role": "title", "responsibilities": "what"}], "risks_identified": [{"risk": "what", "likelihood": "level", "impact": "level", "mitigation": "plan"}], "communication_confirmed": {"slack_channel": "name", "meeting_cadence": "freq", "update_format": "how"}}',
  progress_checkin: '{"milestone_status": [{"milestone": "name", "status": "complete|in_progress|blocked", "notes": "details"}], "blockers_reviewed": [{"blocker_id": "ref", "status": "resolved|open", "resolution": "how"}], "scope_changes": ["changes"], "client_satisfaction": "signal", "next_actions": [{"action": "what", "owner": "who", "due_date": "when"}]}',
  go_no_go: '{"test_results": [{"test_case": "name", "result": "pass|fail", "notes": "details"}], "approval_status": "approved|conditional|rejected", "punch_list": [{"item": "what", "severity": "level", "owner": "who", "due_date": "when"}], "launch_conditions": ["conditions"], "conditional_items": ["items"]}',
  delivery_review: '{"deliverables_reviewed": [{"deliverable": "name", "status": "accepted|needs_revision", "feedback": "notes"}], "client_feedback": "summary", "satisfaction_score": 8, "training_gaps": ["gaps"], "upsell_opportunities": ["opportunities"], "testimonial_consent": true}'
};

const schema = extractionSchemas[meetingData.meetingType] || extractionSchemas.discovery;

let priorContext = '';
if (priorMeetings.length > 0) {
  priorContext = '\n\n--- PRIOR MEETING HISTORY ---\n';
  for (const pm of priorMeetings) {
    priorContext += `\n[${pm.meeting_type}] ${pm.meeting_date || 'Unknown date'}:\n`;
    if (pm.key_decisions && pm.key_decisions.length) priorContext += `Key Decisions: ${JSON.stringify(pm.key_decisions)}\n`;
    if (pm.action_items && pm.action_items.length) priorContext += `Action Items: ${JSON.stringify(pm.action_items)}\n`;
    if (pm.open_questions && pm.open_questions.length) priorContext += `Open Questions: ${JSON.stringify(pm.open_questions)}\n`;
    if (pm.meeting_data) priorContext += `Meeting Data: ${JSON.stringify(pm.meeting_data)}\n`;
  }
}

return [{
