    key_decisions: [], action_items: [],
    open_questions: ['Manual review needed'],
    risks_identified: [], meeting_data: {}
  };
}

const typeLabels = {
  discovery: 'Discovery Call', onboarding: 'Onboarding Call',
  kickoff: 'Kickoff Meeting', progress_checkin: 'Progress Check-in',
  go_no_go: 'Go/No-Go Review', delivery_review: 'Delivery & Review'
};
const typeLabel = typeLabels[ctx.meetingType] || ctx.meetingType;
const emoji = ctx.meetingType === 'delivery_review' ? '\ud83c\udf89' : ctx.meetingType === 'go_no_go' ? '\ud83d\udea6' : '\ud83d\udcdd';

const channelMap = {
  discovery: 'C08F7L8F2PL',
  onboarding: 'C0ABTFRRVN3',
  kickoff: 'C0ABTFRRVN3',
  progress_checkin: 'C0ABTFRRVN3',
  go_no_go: 'C0ABTFRRVN3',
  delivery_review: 'C0AD388QEC8'
};
const slackChannel = channelMap[ctx.meetingType] || 'C0ABTFRRVN3';

const slackSummary = `${emoji} *${typeLabel} Complete: ${ctx.clientName || ctx.clientProject?.client_name || 'Unknown'}*\n\n*Duration:* ${ctx.duration} minutes\n*Recording:* ${ctx.recordingUrl ? '<' + ctx.recordingUrl + '|Watch>' : 'N/A'}\n\n*Summary:* ${structured.structured_notes?.summary || 'N/A'}\n\n*Key Decisions:*\n${(structured.key_decisions || []).map(d => '\u2022 ' + d).join('\n') || 'None'}\n\n*Action Items:*\n${(structured.action_items || []).map((a, i) => (i+1) + '. ' + (a.action || a) + (a.owner ? ' (' + a.owner + ')' : '')).join('\n') || 'None'}\n\n*Open Questions:*\n${(structured.open_questions || []).map(q => '\u2022 ' + q).join('\n') || 'None'}\n\n_Next: ${ctx.nextMeetingType || 'Project complete'}_`;

return {
  ...ctx, structured, slackSummary, slackChannel,
  meetingRecord: {
    client_project_id: ctx.clientProjectId,
    meeting_type: ctx.meetingType,
    calendly_event_uri: ctx.calendlyEventUri || null,
    transcript: ctx.transcript,
    raw_notes: ctx.summary,
    recording_url: ctx.recordingUrl || null,
    structured_notes: JSON.stringify(structured.structured_notes || {}),
    key_decisions: JSON.stringify(structured.key_decisions || []),
    action_items: JSON.stringify(structured.action_items || []),
    open_questions: JSON.stringify(structured.open_questions || []),
    risks_identified: JSON.stringify(structured.risks_identified || []),
    meeting_data: JSON.stringify(structured.meeting_data || {}),
    next_meeting_type: ctx.nextMeetingType,
    meeting_date: ctx.meetingDate,
    duration_minutes: ctx.duration,
    attendees: JSON.stringify(ctx.participants || []),
    read_ai_meeting_id: ctx.readAiMeetingId || null
  }
