const ctx = $('Parse and Store').item.json;
const meetingRecordId = $('Write Meeting Record').item.json.id || null;
const meetingType = ctx.meetingType;
const projectId = ctx.clientProjectId;

const statusUpdates = {
  discovery: { discovery_call_completed_at: new Date().toISOString() },
