    if (cpItems.length > 0 && cpItems[0].json && cpItems[0].json.id) {
      clientProjectId = cpItems[0].json.id;
    }
  } catch (e) {}
}

const meetingRecord = {
  ...parseCtx.meetingRecord,
  contact_submission_id: contactSubmissionId,
  client_project_id: clientProjectId
};

return [{ json: { ...parseCtx, meetingRecord, contactSubmissionId } }];

