  }
}];

const parseCtx = $('Parse and Store').item.json;
let contactSubmissionId = null;
try {
  const leadItems = $('Fetch Lead by Email').all();
  if (leadItems.length > 0 && leadItems[0].json && leadItems[0].json.id) {
    contactSubmissionId = leadItems[0].json.id;
  }
} catch (e) {
  contactSubmissionId = null;
}

let clientProjectId = parseCtx.meetingRecord?.client_project_id || null;
if (!clientProjectId && contactSubmissionId) {
  try {
    const cpItems = $('Fetch Client Project').all();
    if (cpItems.length > 0 && cpItems[0].json && cpItems[0].json.id) {
      clientProjectId = cpItems[0].json.id;
    }
  } catch (e) {}
}

const meetingRecord = {
  ...parseCtx.meetingRecord,
  contact_submission_id: contactSubmissionId,
  client_project_id: clientProjectId
};

return [{ json: { ...parseCtx, meetingRecord, contactSubmissionId } }];
